mapper.select:
SELECT ci.id, ci.user_id, ci.collection_id, ci.source_type, ci.title, ci.source_url, ci.note_id, ci.related_note_id, ci.note_source_label, ci.core_abstract, ci.keywords, ci.study_goal, ci.digest_status, ci.is_read, ci.visit_count, ci.category_id, ci.source, ci.study_progress, ci.created_at, ci.updated_at, t.id AS tag_id, t.name AS tag_name, t.color AS tag_color FROM collection_item ci LEFT JOIN collection_item_tag cit ON ci.id = cit.collection_item_id LEFT JOIN tag t ON cit.tag_id = t.id AND t.deleted = 0 WHERE ci.user_id = #{userId} AND ci.deleted = 0
AND ci.collection_id = #{collectionId}
AND (ci.title LIKE CONCAT('%', #{keyword}, '%') OR ci.core_abstract LIKE CONCAT('%', #{keyword}, '%') OR ci.keywords LIKE CONCAT('%', #{keyword}, '%'))
AND ci.digest_status = #{digestStatus}
AND ci.study_progress = #{studyProgress}
AND ci.category_id = #{categoryId}
AND ci.source_type = #{sourceType}
AND ci.is_read = #{isRead}
ORDER BY ci.updated_at DESC
